2057Ôćĺ+/**
2058Ôćĺ+ * Subscribe to a native IPC event. Returns unsubscribe function.
2059Ôćĺ+ * In web mode, returns a no-op unsubscribe.
2060Ôćĺ+ *
2061Ôćĺ+ * Note: The returned cleanup function is synchronous, but the actual
2062Ôćĺ+ * listener registration is async (listen returns Promise<UnlistenFn>).
2063Ôćĺ+ * For React effects, call the returned fn in the cleanup. If the
2064Ôćĺ+ * listener hasn't resolved yet, it will be cleaned up when it does.
2065Ôćĺ+ */
2066Ôćĺ+export function on<K extends AppEventName>(
2067Ôćĺ+  event: K,
2068Ôćĺ+  callback: (data: AppEventMap[K]) => void
2069Ôćĺ+): () => void {
2070Ôćĺ+  if (!capabilities.ipcEventListeners) return () => {};
2071Ôćĺ+
2072Ôćĺ+  let cleanup: (() => void) | null = null;
2073Ôćĺ+  let cancelled = false;
2074Ôćĺ+
2075Ôćĺ+  // listen() returns Promise<UnlistenFn>
2076Ôćĺ+  listen(event, (e) => callback(e.payload as AppEventMap[K]))
2077Ôćĺ+    .then((unlisten) => {
2078Ôćĺ+      if (cancelled) {
2079Ôćĺ+        unlisten();
2080Ôćĺ+      } else {
2081Ôćĺ+        cleanup = unlisten;
2082Ôćĺ+      }
2083Ôćĺ+    })
2084Ôćĺ+    .catch(() => {});
2085Ôćĺ+
2086Ôćĺ+  return () => {
2087Ôćĺ+    cancelled = true;
2088Ôćĺ+    cleanup?.();
2089Ôćĺ+  };
2090Ôćĺ+}
