 82Ôćĺ * frameworks (React, Next.js, etc.) can hydrate before we snapshot.
 83Ôćĺ */
 84Ôćĺasync function waitForPageLoad(
 85Ôćĺ  label: string,
 86Ôćĺ  timeoutMs = 15_000,
 87Ôćĺ  settleMs = 500,
 88Ôćĺ  alsoListenUrlChange = false
 89Ôćĺ): Promise<string> {
 90Ôćĺ  return new Promise<string>((resolve, reject) => {
 91Ôćĺ    let settled = false;
 92Ôćĺ    const unlistenFns: (() => void)[] = [];
 93Ôćĺ
 94Ôćĺ    function cleanup() {
 95Ôćĺ      for (const fn of unlistenFns) fn();
 96Ôćĺ    }
 97Ôćĺ
 98Ôćĺ    const timer = setTimeout(() => {
 99Ôćĺ      if (!settled) {
100Ôćĺ        settled = true;
101Ôćĺ        cleanup();
102Ôćĺ        reject(new Error(`Page did not finish loading within ${timeoutMs}ms`));
103Ôćĺ      }
104Ôćĺ    }, timeoutMs);
105Ôćĺ
106Ôćĺ    function onLoad(url: string) {
107Ôćĺ      if (!settled) {
108Ôćĺ        settled = true;
109Ôćĺ        clearTimeout(timer);
110Ôćĺ        cleanup();
111Ôćĺ        // Short settle for framework hydration (React, Next.js, etc.)
112Ôćĺ        setTimeout(() => resolve(url), settleMs);
113Ôćĺ      }
114Ôćĺ    }
115Ôćĺ
116Ôćĺ    // Primary: browser:page-load (real navigations)
117Ôćĺ    const unlistenPageLoad = native.events.on(BROWSER_PAGE_LOAD, (data) => {
118Ôćĺ      const payload = data as { label: string; event: string; url: string };
119Ôćĺ      if (payload.label === label && payload.event === "finished") {
120Ôćĺ        onLoad(payload.url);
121Ôćĺ      }
122Ôćĺ    });
123Ôćĺ    unlistenFns.push(unlistenPageLoad);
124Ôćĺ
125Ôćĺ    // Secondary: browser:url-change (SPA navigations via popstate)
126Ôćĺ    if (alsoListenUrlChange) {
127Ôćĺ      const unlistenUrlChange = native.events.on(BROWSER_URL_CHANGE, (data) => {
128Ôćĺ        const payload = data as { label: string; url: string };
129Ôćĺ        if (payload.label === label) {
130Ôćĺ          onLoad(payload.url);
131Ôćĺ        }
132Ôćĺ      });
133Ôćĺ      unlistenFns.push(unlistenUrlChange);
134Ôćĺ    }
135Ôćĺ  });
136Ôćĺ}
