864Ôćĺ      if (!label) {
865Ôćĺ        respond({ success: false, error: "No active browser tab" });
866Ôćĺ        return;
867Ôćĺ      }
868Ôćĺ
869Ôćĺ      const direction = params.direction as string | undefined;
870Ôćĺ      const amount = params.amount as number | undefined;
871Ôćĺ      const ref = params.ref as string | undefined;
