  1Ôćĺ/**
  2Ôćĺ * API Configuration
  3Ôćĺ * Central configuration for API endpoints and settings
  4Ôćĺ *
  5Ôćĺ * Port resolution:
  6Ôćĺ * - Electron app: Uses preload bridge via window.electronAPI.getBackendPort()
  7Ôćĺ * - Web dev: Uses VITE_BACKEND_PORT environment variable from dev.sh
  8Ôćĺ */
  9Ôćĺ
 10Ôćĺ// Import directly from the source module (not the barrel) to avoid circular
 11Ôćĺ// dependency: client.ts Ôćĺ api.config.ts Ôćĺ platform/electron/index.ts Ôćĺ ... Ôćĺ client.ts
 12Ôćĺimport { isElectronEnv } from "@/platform/electron/invoke";
 13Ôćĺ
 14Ôćĺlet cachedPort: number | null = null;
 15Ôćĺlet portPromise: Promise<number> | null = null;
 16Ôćĺ
 17Ôćĺ// IPC retry config for backend port resolution.
 18Ôćĺ// The backend may not have emitted its [BACKEND_PORT] marker yet during early
 19Ôćĺ// startup ÔÇö the main process waits for it before returning the port.
 20Ôćĺ// 30 attempts ├Ś 200ms = 6s covers the startup timeout with margin.
 21Ôćĺconst PORT_MAX_RETRIES = 30;
 22Ôćĺconst PORT_RETRY_DELAY_MS = 200;
 23Ôćĺ
 24Ôćĺ/**
 25Ôćĺ * Get the backend port (cached after first call).
 26Ôćĺ *
 27Ôćĺ * In Electron mode, retries the IPC call with backoff because the backend may
 28Ôćĺ * still be starting when the renderer first loads. Without retries, a single
 29Ôćĺ * failed invoke permanently caches port 3333, causing all API requests to
 30Ôćĺ * hit the wrong port and leaving the window hidden.
 31Ôćĺ */
 32Ôćĺexport async function getBackendPort(): Promise<number> {
 33Ôćĺ  if (cachedPort !== null) {
 34Ôćĺ    return cachedPort;
 35Ôćĺ  }
 36Ôćĺ
 37Ôćĺ  // If there's already a pending request, return it
 38Ôćĺ  if (portPromise !== null) {
 39Ôćĺ    return portPromise;
 40Ôćĺ  }
 41Ôćĺ
 42Ôćĺ  portPromise = (async () => {
 43Ôćĺ    // 1. Check if running in web dev mode with dynamic port
 44Ôćĺ    if (import.meta.env.VITE_BACKEND_PORT) {
 45Ôćĺ      const port = parseInt(import.meta.env.VITE_BACKEND_PORT as string, 10);
 46Ôćĺ      if (!isNaN(port)) {
 47Ôćĺ        if (import.meta.env.DEV) console.log(`[API] Using web dev backend port: ${port}`);
 48Ôćĺ        cachedPort = port;
 49Ôćĺ        return port;
 50Ôćĺ      }
 51Ôćĺ    }
 52Ôćĺ
 53Ôćĺ    // 2. Electron: use the dedicated preload API (bypasses generic invoke bridge).
 54Ôćĺ    // The backend is spawned by the main process before the window is created,
 55Ôćĺ    // so the port should be available immediately via native:getBackendPort.
 56Ôćĺ    // Retry with backoff for the rare case where the renderer loads before the
 57Ôćĺ    // backend has emitted its [BACKEND_PORT] marker.
 58Ôćĺ    if (isElectronEnv) {
 59Ôćĺ      for (let attempt = 0; attempt < PORT_MAX_RETRIES; attempt++) {
 60Ôćĺ        try {
 61Ôćĺ          const port = await window.electronAPI!.getBackendPort();
 62Ôćĺ          if (import.meta.env.DEV)
 63Ôćĺ            console.log(`[API] Using Electron backend port: ${port} (attempt ${attempt + 1})`);
 64Ôćĺ          cachedPort = port;
 65Ôćĺ          return port;
 66Ôćĺ        } catch {
 67Ôćĺ          if (attempt < PORT_MAX_RETRIES - 1) {
 68Ôćĺ            await new Promise((resolve) => setTimeout(resolve, PORT_RETRY_DELAY_MS));
 69Ôćĺ          }
 70Ôćĺ        }
 71Ôćĺ      }
 72Ôćĺ      // All retries exhausted ÔÇö don't cache a wrong port. Throw so TanStack Query
 73Ôćĺ      // retries the entire fetch later, giving the backend more time to start.
 74Ôćĺ      console.error("[API] getBackendPort failed after retries ÔÇö backend may not have started");
 75Ôćĺ      throw new Error("Backend port not available after retries");
 76Ôćĺ    }
 77Ôćĺ
 78Ôćĺ    // 3. Dev mode: fetch port from Vite middleware (Electron writes it to temp file).
 79Ôćĺ    // This enables Chrome tabs at localhost:1420 to work during `bun run dev`.
 80Ôćĺ    if (import.meta.env.DEV) {
 81Ôćĺ      try {
 82Ôćĺ        const res = await fetch("/__backend_port");
 83Ôćĺ        if (res.ok) {
 84Ôćĺ          const data = await res.json();
 85Ôćĺ          if (data.port && typeof data.port === "number") {
 86Ôćĺ            console.log(`[API] Using backend port from dev server: ${data.port}`);
 87Ôćĺ            cachedPort = data.port;
 88Ôćĺ            return data.port;
 89Ôćĺ          }
 90Ôćĺ        }
 91Ôćĺ      } catch {
 92Ôćĺ        // Vite middleware not available
 93Ôćĺ      }
 94Ôćĺ    }
 95Ôćĺ
 96Ôćĺ    // 4. Last resort fallback ÔÇö do NOT cache so retries re-resolve
 97Ôćĺ    // (e.g. user clicks Retry after backend finishes starting)
 98Ôćĺ    console.warn("[API] No port source available, falling back to default port 3333");
 99Ôćĺ    return 3333;
100Ôćĺ  })();
101Ôćĺ
102Ôćĺ  // Clear promise when done (success or failure)
103Ôćĺ  portPromise.finally(() => {
104Ôćĺ    portPromise = null;
105Ôćĺ  });
106Ôćĺ
107Ôćĺ  return portPromise;
108Ôćĺ}
109Ôćĺ
110Ôćĺ/**
111Ôćĺ * Set the backend port directly and clear any in-flight resolution.
112Ôćĺ * Called when the main process notifies the renderer of a backend restart
113Ôćĺ * with a new port ÔÇö the WebSocket reconnect loop will pick up the new port
114Ôćĺ * on its next `getBackendPort()` call (which returns immediately from cache).
115Ôćĺ */
116Ôćĺexport function setBackendPort(port: number): void {
117Ôćĺ  cachedPort = port;
118Ôćĺ  portPromise = null;
119Ôćĺ  if (import.meta.env.DEV) {
120Ôćĺ    console.log(`[API] Backend port updated to ${port} (backend restarted)`);
121Ôćĺ  }
122Ôćĺ}
