 21Ôćĺ    name: "opendevs-backend-port",
 22Ôćĺ    configureServer(server) {
 23Ôćĺ      server.middlewares.use((req, res, next) => {
 24Ôćĺ        if (req.url === "/__backend_port") {
 25Ôćĺ          const portFile = join(tmpdir(), "opendevs-backend-port");
 26Ôćĺ          try {
 27Ôćĺ            if (existsSync(portFile)) {
 28Ôćĺ              const port = readFileSync(portFile, "utf-8").trim();
 29Ôćĺ              res.setHeader("Content-Type", "application/json");
 30Ôćĺ              res.setHeader("Access-Control-Allow-Origin", "*");
 31Ôćĺ              res.end(JSON.stringify({ port: parseInt(port, 10) }));
 32Ôćĺ              return;
 33Ôćĺ            }
 34Ôćĺ          } catch {
 35Ôćĺ            // Port file not readable ÔÇö fall through to 503
 36Ôćĺ          }
 37Ôćĺ          res.statusCode = 503;
 38Ôćĺ          res.end(JSON.stringify({ error: "Backend not started yet" }));
 39Ôćĺ          return;
 40Ôćĺ        }
 41Ôćĺ        next();
 42Ôćĺ      });
 43Ôćĺ    },
 44Ôćĺ  };
 45Ôćĺ}
