 37Ôćĺ    (window as { __APP_LAST_COMPONENT_STACK__?: string }).__APP_LAST_COMPONENT_STACK__ =
 38Ôćĺ      info.componentStack ?? undefined;
 39Ôćĺ  };
 40Ôćĺ}
 41Ôćĺ
 42Ôćĺ/**
 43Ôćĺ * Gates between onboarding and the main app.
 44Ôćĺ *
 45Ôćĺ * When onboarding is active, ONLY OnboardingOverlay renders ÔÇö no MainLayout,
 46Ôćĺ * no sidebar, no workspace panels. This ensures the transparent window shows
 47Ôćĺ * the desktop through the semi-transparent scrim, not the app's own UI.
 48Ôćĺ */
 49Ôćĺfunction AppContent({ reset }: { reset: () => void }) {
 50Ôćĺ  const auth = useAuth();
 51Ôćĺ  const settingsQuery = useSettings();
 52Ôćĺ  const windowShownRef = useRef(false);
 53Ôćĺ
 54Ôćĺ  // Request OS notification permission once on mount
 55Ôćĺ  useEffect(() => {
 56Ôćĺ    initNotifications();
 57Ôćĺ  }, []);
 58Ôćĺ
 59Ôćĺ  // Global listener: fire OS notifications for ALL session events when backgrounded
 60Ôćĺ  useGlobalSessionNotifications();
 61Ôćĺ
 62Ôćĺ  // Global listener: workspace init progress Ôćĺ invalidate queries on completion
 63Ôćĺ  useWorkspaceInitEvents();
 64Ôćĺ
 65Ôćĺ  // Global listener: WS query protocol Ôćĺ direct cache updates + invalidation dispatch
 66Ôćĺ  useQueryProtocol();
 67Ôćĺ
 68Ôćĺ  // Global listener: backend restart Ôćĺ update cached port + force WS reconnect
 69Ôćĺ  useBackendRestart();
 70Ôćĺ
 71Ôćĺ  // Sync PostHog opt-in/out state with analytics_enabled setting
 72Ôćĺ  useAnalyticsConsent();
 73Ôćĺ
 74Ôćĺ  // Auto-update: check on launch + every 5 min, show toast when ready
 75Ôćĺ  const autoUpdate = useAutoUpdate();
 76Ôćĺ  useUpdateToast(autoUpdate);
 77Ôćĺ
 78Ôćĺ  const showOnboarding = !settingsQuery.isError && !settingsQuery.data?.onboarding_completed;
 79Ôćĺ
 80Ôćĺ  // Boot diagnostics ÔÇö trace the window-show flow so we can see what's blocking
 81Ôćĺ  useEffect(() => {
 82Ôćĺ    if (import.meta.env.DEV) {
 83Ôćĺ      console.log("[App] AppContent mount ÔÇö auth:", {
 84Ôćĺ        isLoading: auth.isLoading,
 85Ôćĺ        isAuthenticated: auth.isAuthenticated,
 86Ôćĺ      });
 87Ôćĺ      console.log("[App] AppContent mount ÔÇö settings:", {
 88Ôćĺ        isLoading: settingsQuery.isLoading,
 89Ôćĺ        isError: settingsQuery.isError,
 90Ôćĺ        hasData: !!settingsQuery.data,
 91Ôćĺ        onboardingCompleted: settingsQuery.data?.onboarding_completed,
 92Ôćĺ        showOnboarding,
 93Ôćĺ      });
 94Ôćĺ    }
 95Ôćĺ  }, [
 96Ôćĺ    auth.isLoading,
 97Ôćĺ    auth.isAuthenticated,
 98Ôćĺ    settingsQuery.isLoading,
 99Ôćĺ    settingsQuery.isError,
100Ôćĺ    settingsQuery.data,
101Ôćĺ    showOnboarding,
102Ôćĺ  ]);
103Ôćĺ
104Ôćĺ  // Show the main window whenever we transition OUT of onboarding.
105Ôćĺ  // Covers both first launch (window starts hidden, show: false in createWindow)
106Ôćĺ  // and replay-onboarding (exit_onboarding_mode hides the window).
107Ôćĺ  useEffect(() => {
108Ôćĺ    if (settingsQuery.isLoading) return;
109Ôćĺ    if (showOnboarding) {
110Ôćĺ      // Entering onboarding ÔÇö reset so we re-show when it completes
111Ôćĺ      windowShownRef.current = false;
112Ôćĺ      return;
113Ôćĺ    }
114Ôćĺ    if (windowShownRef.current) return;
115Ôćĺ    native.window.show().catch(console.error);
116Ôćĺ    windowShownRef.current = true;
117Ôćĺ  }, [settingsQuery.isLoading, showOnboarding]);
118Ôćĺ
119Ôćĺ  // Remote browser auth gate: show pairing page if not authenticated
120Ôćĺ  if (auth.isLoading) return null;
121Ôćĺ  if (!auth.isAuthenticated) return <PairGatePage onPaired={auth.onPaired} />;
122Ôćĺ
123Ôćĺ  // While settings load, render nothing ÔÇö window is hidden anyway
124Ôćĺ  if (settingsQuery.isLoading) return null;
125Ôćĺ
126Ôćĺ  // Backend unreachable ÔÇö show error instead of white screen
127Ôćĺ  if (settingsQuery.isError && !settingsQuery.data) {
128Ôćĺ    return (
129Ôćĺ      <div className="bg-background flex h-screen items-center justify-center">
130Ôćĺ        <div className="max-w-md space-y-4 text-center">
131Ôćĺ          <h1 className="text-foreground text-xl font-semibold">Cannot connect to backend</h1>
132Ôćĺ          <p className="text-muted-foreground text-sm">
133Ôćĺ            {capabilities.windowLifecycle
134Ôćĺ              ? "The backend server failed to start. Check the terminal for errors."
135Ôćĺ              : "Run `bun run dev:web` for browser development, or use the Electron desktop app (`bun run dev`)."}
136Ôćĺ          </p>
137Ôćĺ          <button
138Ôćĺ            type="button"
139Ôćĺ            onClick={() => settingsQuery.refetch()}
140Ôćĺ            className="bg-primary text-primary-foreground hover:bg-primary/90 rounded-lg px-4 py-2 text-sm font-medium"
141Ôćĺ          >
142Ôćĺ            Retry
143Ôćĺ          </button>
144Ôćĺ        </div>
145Ôćĺ      </div>
146Ôćĺ    );
147Ôćĺ  }
148Ôćĺ
149Ôćĺ  if (showOnboarding) {
150Ôćĺ    return <OnboardingOverlay />;
151Ôćĺ  }
152Ôćĺ
153Ôćĺ  return (
154Ôćĺ    <UpdateProvider value={autoUpdate}>
155Ôćĺ      <BrowserRouter>
156Ôćĺ        <Routes>
157Ôćĺ          <Route
158Ôćĺ            path="/"
159Ôćĺ            element={
160Ôćĺ              <ErrorBoundary
161Ôćĺ                FallbackComponent={DashboardError}
162Ôćĺ                onReset={reset}
163Ôćĺ                onError={createBoundaryErrorHandler("react.error-boundary.root")}
164Ôćĺ              >
165Ôćĺ                <MainLayout />
166Ôćĺ              </ErrorBoundary>
167Ôćĺ            }
168Ôćĺ          />
169Ôćĺ        </Routes>
170Ôćĺ      </BrowserRouter>
171Ôćĺ      <Toaster />
172Ôćĺ    </UpdateProvider>
173Ôćĺ  );
174Ôćĺ}
175Ôćĺ
176Ôćĺ/**
177Ôćĺ * Safety net: ensure the window always becomes visible.
178Ôćĺ *
179Ôćĺ * The main window starts hidden (show: false in createWindow) to avoid
180Ôćĺ * a flash before onboarding/content is ready. Normally the frontend calls
181Ôćĺ * show_main_window or enter_onboarding_mode within ~1-2s. But if anything
182Ôćĺ * goes wrong (settings fetch hangs, unexpected error, hook crash), the window
183Ôćĺ * stays hidden and the user sees only a dock icon with no window.
184Ôćĺ *
185Ôćĺ * This timeout guarantees the window appears within WINDOW_SHOW_TIMEOUT_MS,
186Ôćĺ * no matter what. It's a last resort ÔÇö the normal flow or ErrorFallback
187Ôćĺ * should show the window sooner.
188Ôćĺ */
189Ôćĺconst WINDOW_SHOW_TIMEOUT_MS = 5_000;
190Ôćĺ
191Ôćĺfunction useWindowShowSafetyNet() {
192Ôćĺ  const shownRef = useRef(false);
193Ôćĺ  useEffect(() => {
194Ôćĺ    if (shownRef.current || !capabilities.windowLifecycle) return;
195Ôćĺ    const timer = setTimeout(() => {
196Ôćĺ      if (!shownRef.current) {
197Ôćĺ        shownRef.current = true;
198Ôćĺ        console.warn("[App] Safety net: force-showing window after timeout");
199Ôćĺ        native.window.show().catch(console.error);
200Ôćĺ      }
201Ôćĺ    }, WINDOW_SHOW_TIMEOUT_MS);
202Ôćĺ    return () => clearTimeout(timer);
203Ôćĺ  }, []);
204Ôćĺ}
205Ôćĺ
206Ôćĺfunction App() {
207Ôćĺ  // Safety net ÔÇö force-show window if nothing else does within 5s
208Ôćĺ  useWindowShowSafetyNet();
209Ôćĺ
210Ôćĺ  const content = isDetachedBrowser ? (
211Ôćĺ    // Detached browser window: minimal shell with just the browser panel
212Ôćĺ    <QueryClientProvider>
213Ôćĺ      <ThemeProvider>
214Ôćĺ        <DetachedBrowserWindow />
215Ôćĺ      </ThemeProvider>
216Ôćĺ    </QueryClientProvider>
217Ôćĺ  ) : (
218Ôćĺ    <QueryClientProvider>
219Ôćĺ      <QueryErrorResetBoundary>
220Ôćĺ        {({ reset }) => (
221Ôćĺ          <ErrorBoundary
222Ôćĺ            FallbackComponent={ErrorFallback}
223Ôćĺ            onReset={reset}
224Ôćĺ            onError={createBoundaryErrorHandler("react.error-boundary")}
225Ôćĺ          >
226Ôćĺ            <ThemeProvider>
227Ôćĺ              <AppContent reset={reset} />
228Ôćĺ            </ThemeProvider>
229Ôćĺ          </ErrorBoundary>
230Ôćĺ        )}
231Ôćĺ      </QueryErrorResetBoundary>
232Ôćĺ    </QueryClientProvider>
233Ôćĺ  );
234Ôćĺ
235Ôćĺ  return (
236Ôćĺ    <LazyMotion features={domAnimation} strict>
237Ôćĺ      {content}
238Ôćĺ    </LazyMotion>
239Ôćĺ  );
240Ôćĺ}
241Ôćĺ
242Ôćĺexport default App;
